arguments.file_text:
#:property AllowUnsafeBlocks=true

Console.WriteLine($"nint size: {nint.Size} bytes");
Console.WriteLine($"nuint size: {nuint.Size} bytes");

// stackalloc Span<nint>
Span<nint> signed = stackalloc nint[4];
for (int i = 0; i < signed.Length; i++)
    signed[i] = i * 10;

Console.Write("Span<nint>:  ");
foreach (var v in signed) Console.Write($"{v} ");
Console.WriteLine();

// stackalloc Span<nuint>
Span<nuint> unsigned = stackalloc nuint[4];
for (int i = 0; i < unsigned.Length; i++)
    unsigned[i] = (nuint)(i * 100);

Console.Write("Span<nuint>: ");
foreach (var v in unsigned) Console.Write($"{v} ");
Console.WriteLine();

Console.WriteLine("Success — stackalloc with nint/nuint works!");

